  setSaving(false);
  if (!res.ok) {
    setError(readApiErrorMessage(body, "Reorder failed"));
    return false;
  }
  const data = body as { sessions?: SessionRow[] };
  if (Array.isArray(data.sessions)) {
    const next = sortSessionsByPosition(data.sessions);
    setItems(next);
    onSessionsChanged?.(next);
  }
  return true;
}

